"""
T2 RBAC System — Auth Routes (Sample 2)

Variant strategy:
- No external decorators; JWT encoding/decoding done inline
- Helper function for response building
- Early-return error pattern

Register as Flask Blueprint named 'auth_bp'.
"""

import jwt as pyjwt
import datetime
from flask import Blueprint, request, jsonify, current_app
from models import User
from middleware import hash_password

auth_bp = Blueprint('auth_bp', __name__)


def _ok(data):
    """Build a success response."""
    return jsonify({'status': 'ok', 'data': data})


def _err(message, status):
    """Build an error response."""
    return jsonify({'status': 'error', 'message': message}), status


@auth_bp.route('/login', methods=['POST'])
def login():
    body = request.get_json(silent=True)
    if not body:
        return _err('Missing request body', 400)

    username = body.get('username')
    password = body.get('password')

    if not username or not password:
        return _err('Username and password are required', 400)

    user = User.query.filter_by(username=username).first()
    if user is None:
        return _err('Invalid credentials', 401)

    if user.password_hash != hash_password(password):
        return _err('Invalid credentials', 401)

    secret = current_app.config.get('JWT_SECRET', 'dev-secret-key')
    expiry_hours = current_app.config.get('JWT_EXPIRY_HOURS', 24)
    exp = datetime.datetime.utcnow() + datetime.timedelta(hours=expiry_hours)

    token = pyjwt.encode(
        {'user_id': user.id, 'tenant_id': user.tenant_id, 'exp': exp},
        secret,
        algorithm='HS256'
    )

    return _ok({'token': token})

"""
T2 RBAC System — Document Routes (Sample 2)

Variant strategy:
- require_auth decorator for authentication, then manual permission checks
- Helper functions for response building and document serialization
- Early-return error pattern
- Owner check helper for PUT

Register as Flask Blueprint named 'document_bp'.
"""

from flask import Blueprint, request, jsonify, g
from middleware import require_auth
from models import Document
from app import db

document_bp = Blueprint('document_bp', __name__)


def _ok(data, status=200):
    return jsonify({'status': 'ok', 'data': data}), status


def _err(message, status):
    return jsonify({'status': 'error', 'message': message}), status


def _serialize(doc):
    """Convert a Document model instance to a dict."""
    return {
        'id': doc.id,
        'tenant_id': doc.tenant_id,
        'owner_id': doc.owner_id,
        'title': doc.title,
        'content': doc.content,
    }


def _check_perm(code):
    """Check if the current user (in g) has a specific permission.
    Returns True/False.
    """
    return code in g.get('current_permissions', set())


@document_bp.route('/documents', methods=['GET'])
@require_auth
def list_documents():
    if not _check_perm('doc.read'):
        return _err('Permission denied', 403)

    tenant_id = g.current_user.tenant_id
    docs = Document.query.filter_by(tenant_id=tenant_id).all()
    return _ok([_serialize(d) for d in docs])


@document_bp.route('/documents/<int:doc_id>', methods=['GET'])
@require_auth
def get_document(doc_id):
    if not _check_perm('doc.read'):
        return _err('Permission denied', 403)

    doc = Document.query.get(doc_id)
    if doc is None or doc.tenant_id != g.current_user.tenant_id:
        return _err('Document not found', 404)

    return _ok(_serialize(doc))


@document_bp.route('/documents', methods=['POST'])
@require_auth
def create_document():
    if not _check_perm('doc.write'):
        return _err('Permission denied', 403)

    body = request.get_json(silent=True)
    if not body:
        return _err('Missing request body', 400)

    title = body.get('title')
    if not title:
        return _err('Title is required', 400)

    doc = Document(
        tenant_id=g.current_user.tenant_id,
        owner_id=g.current_user.id,
        title=title,
        content=body.get('content', ''),
    )
    db.session.add(doc)
    db.session.commit()

    return _ok(_serialize(doc), 201)


@document_bp.route('/documents/<int:doc_id>', methods=['PUT'])
@require_auth
def update_document(doc_id):
    if not _check_perm('doc.write'):
        return _err('Permission denied', 403)

    doc = Document.query.get(doc_id)
    if doc is None:
        return _err('Document not found', 404)

    # Owner or doc.write.any check
    is_owner = doc.owner_id == g.current_user.id
    has_write_any = _check_perm('doc.write.any')
    if not is_owner and not has_write_any:
        return _err('Permission denied', 403)

    body = request.get_json(silent=True)
    if body:
        if 'title' in body:
            doc.title = body['title']
        if 'content' in body:
            doc.content = body['content']

    db.session.commit()
    return _ok(_serialize(doc))


@document_bp.route('/documents/<int:doc_id>', methods=['DELETE'])
@require_auth
def delete_document(doc_id):
    if not _check_perm('doc.delete'):
        return _err('Permission denied', 403)

    doc = Document.query.get(doc_id)
    if doc is None or doc.tenant_id != g.current_user.tenant_id:
        return _err('Document not found', 404)

    db.session.delete(doc)
    db.session.commit()
    return _ok({'deleted': doc_id})

"""
T2 RBAC System -- Document Routes (Sample 1)

Strategy: Decorator-based permission checks using middleware.check_permission.
Direct SQLAlchemy model operations inside route handlers -- no service layer.
Simple if-else error handling pattern.

Design decisions:
- Uses middleware.check_permission decorator for RBAC enforcement
- For PUT: additional owner/doc.write.any check inside the handler
  (the decorator grants doc.write, then handler checks ownership)
- Tenant isolation: all queries filter by g.current_user.tenant_id
- DELETE requires doc.delete + same tenant (returns 404 for cross-tenant)
"""

from flask import Blueprint, request, jsonify, g
from models import Document
from middleware import check_permission
from app import db

document_bp = Blueprint('document_bp', __name__)


def _doc_to_dict(doc):
    """Convert Document model instance to dict for JSON response."""
    return {
        'id': doc.id,
        'tenant_id': doc.tenant_id,
        'owner_id': doc.owner_id,
        'title': doc.title,
        'content': doc.content,
    }


@document_bp.route('/documents', methods=['GET'])
@check_permission('doc.read')
def list_documents():
    docs = Document.query.filter_by(tenant_id=g.current_user.tenant_id).all()
    return jsonify({'status': 'ok', 'data': [_doc_to_dict(d) for d in docs]}), 200


@document_bp.route('/documents/<int:doc_id>', methods=['GET'])
@check_permission('doc.read')
def get_document(doc_id):
    doc = Document.query.filter_by(id=doc_id, tenant_id=g.current_user.tenant_id).first()
    if doc is None:
        return jsonify({'status': 'error', 'message': 'Document not found'}), 404
    return jsonify({'status': 'ok', 'data': _doc_to_dict(doc)}), 200


@document_bp.route('/documents', methods=['POST'])
@check_permission('doc.write')
def create_document():
    data = request.get_json(silent=True) or {}
    title = data.get('title', '')
    content = data.get('content', '')

    doc = Document(
        tenant_id=g.current_user.tenant_id,
        owner_id=g.current_user.id,
        title=title,
        content=content,
    )
    db.session.add(doc)
    db.session.commit()

    return jsonify({'status': 'ok', 'data': _doc_to_dict(doc)}), 201


@document_bp.route('/documents/<int:doc_id>', methods=['PUT'])
@check_permission('doc.write')
def update_document(doc_id):
    doc = Document.query.filter_by(id=doc_id, tenant_id=g.current_user.tenant_id).first()
    if doc is None:
        return jsonify({'status': 'error', 'message': 'Document not found'}), 404

    # Owner check: allow if owner, or if user has doc.write.any permission
    if doc.owner_id != g.current_user.id:
        if 'doc.write.any' not in g.current_permissions:
            return jsonify({'status': 'error', 'message': 'Permission denied'}), 403

    data = request.get_json(silent=True) or {}
    if 'title' in data:
        doc.title = data['title']
    if 'content' in data:
        doc.content = data['content']
    db.session.commit()

    return jsonify({'status': 'ok', 'data': _doc_to_dict(doc)}), 200


@document_bp.route('/documents/<int:doc_id>', methods=['DELETE'])
@check_permission('doc.delete')
def delete_document(doc_id):
    doc = Document.query.filter_by(id=doc_id, tenant_id=g.current_user.tenant_id).first()
    if doc is None:
        return jsonify({'status': 'error', 'message': 'Document not found'}), 404

    db.session.delete(doc)
    db.session.commit()
    return jsonify({'status': 'ok', 'data': None}), 200

"""
T2 RBAC System — Role Management Routes (Sample 2)

Variant strategy:
- require_auth decorator for authentication, then manual role.manage check
- Helper functions for response building and role serialization
- BFS-based inheritance cycle detection (not recursive)
- Early-return error pattern

Register as Flask Blueprint named 'role_bp'.
"""

from collections import deque
from flask import Blueprint, request, jsonify, g
from middleware import require_auth
from models import Role, Permission, User, role_permissions, user_roles
from app import db

role_bp = Blueprint('role_bp', __name__)


def _ok(data, status=200):
    return jsonify({'status': 'ok', 'data': data}), status


def _err(message, status):
    return jsonify({'status': 'error', 'message': message}), status


def _serialize_role(role):
    """Convert a Role model instance to a dict including its direct permissions."""
    return {
        'id': role.id,
        'name': role.name,
        'parent_role_id': role.parent_role_id,
        'permissions': [p.code for p in role.permissions],
    }


def _check_perm(code):
    """Check if the current user has a specific permission."""
    return code in g.get('current_permissions', set())


def _has_inheritance_cycle(role_id, target_parent_id):
    """Detect if setting role_id's parent to target_parent_id would create a cycle.

    Uses BFS/iteration: walk the parent chain upward from target_parent_id.
    If we encounter role_id along the way, setting this parent would create a cycle.

    Returns True if a cycle would be formed.
    """
    visited = set()
    queue = deque([target_parent_id])

    while queue:
        current_id = queue.popleft()
        if current_id == role_id:
            return True
        if current_id in visited:
            continue
        visited.add(current_id)

        current_role = Role.query.get(current_id)
        if current_role and current_role.parent_role_id is not None:
            queue.append(current_role.parent_role_id)

    return False


def _resolve_permissions(perm_codes):
    """Look up Permission records by code strings. Returns (list, error_response).
    If any code is not found, returns ([], error).
    """
    if not perm_codes:
        return [], None

    perms = Permission.query.filter(Permission.code.in_(perm_codes)).all()
    found_codes = {p.code for p in perms}
    missing = set(perm_codes) - found_codes
    if missing:
        return [], _err(f'Unknown permissions: {", ".join(sorted(missing))}', 400)
    return perms, None


@role_bp.route('/roles', methods=['POST'])
@require_auth
def create_role():
    if not _check_perm('role.manage'):
        return _err('Permission denied', 403)

    body = request.get_json(silent=True)
    if not body:
        return _err('Missing request body', 400)

    name = body.get('name')
    if not name:
        return _err('Role name is required', 400)

    tenant_id = g.current_user.tenant_id

    # Check duplicate name within tenant
    existing = Role.query.filter_by(tenant_id=tenant_id, name=name).first()
    if existing:
        return _err(f'Role "{name}" already exists in this tenant', 409)

    parent_role_id = body.get('parent_role_id')
    if parent_role_id is not None:
        parent = Role.query.get(parent_role_id)
        if parent is None or parent.tenant_id != tenant_id:
            return _err('Parent role not found or belongs to a different tenant', 400)

    perms, err = _resolve_permissions(body.get('permissions', []))
    if err:
        return err

    role = Role(tenant_id=tenant_id, name=name, parent_role_id=parent_role_id)
    role.permissions = perms
    db.session.add(role)
    db.session.commit()

    return _ok(_serialize_role(role), 201)


@role_bp.route('/roles', methods=['GET'])
@require_auth
def list_roles():
    if not _check_perm('role.manage'):
        return _err('Permission denied', 403)

    tenant_id = g.current_user.tenant_id
    roles = Role.query.filter_by(tenant_id=tenant_id).all()
    return _ok([_serialize_role(r) for r in roles])


@role_bp.route('/roles/<int:role_id>/permissions', methods=['PUT'])
@require_auth
def update_role_permissions(role_id):
    if not _check_perm('role.manage'):
        return _err('Permission denied', 403)

    role = Role.query.get(role_id)
    if role is None:
        return _err('Role not found', 404)

    body = request.get_json(silent=True)
    if not body:
        return _err('Missing request body', 400)

    parent_role_id = body.get('parent_role_id')
    if parent_role_id is not None:
        # Validate parent belongs to same tenant
        parent = Role.query.get(parent_role_id)
        if parent is None or parent.tenant_id != role.tenant_id:
            return _err('Parent role not found or belongs to a different tenant', 400)

        # Cycle detection: would setting parent_role_id on role_id create a cycle?
        if _has_inheritance_cycle(role_id, parent_role_id):
            return _err('Inheritance cycle detected', 400)

        role.parent_role_id = parent_role_id
    else:
        # Explicitly clear parent if parent_role_id is None in body
        if 'parent_role_id' in body:
            role.parent_role_id = None

    # Replace permissions
    perm_codes = body.get('permissions')
    if perm_codes is not None:
        perms, err = _resolve_permissions(perm_codes)
        if err:
            return err
        role.permissions = perms

    db.session.commit()
    return _ok(_serialize_role(role))


@role_bp.route('/users/<int:user_id>/roles', methods=['POST'])
@require_auth
def assign_role(user_id):
    if not _check_perm('role.manage'):
        return _err('Permission denied', 403)

    body = request.get_json(silent=True)
    if not body:
        return _err('Missing request body', 400)

    role_id = body.get('role_id')
    if role_id is None:
        return _err('role_id is required', 400)

    user = User.query.get(user_id)
    if user is None:
        return _err('User not found', 404)

    role = Role.query.get(role_id)
    if role is None:
        return _err('Role not found', 404)

    # Cross-tenant check
    if user.tenant_id != g.current_user.tenant_id:
        return _err('Cannot assign roles to users in other tenants', 403)

    if role.tenant_id != g.current_user.tenant_id:
        return _err('Cannot assign roles from other tenants', 403)

    # Check if already assigned (avoid duplicate insert)
    existing = db.session.query(user_roles).filter_by(
        user_id=user_id, role_id=role_id
    ).first()
    if existing:
        return _ok({'user_id': user_id, 'role_id': role_id})

    db.session.execute(user_roles.insert().values(user_id=user_id, role_id=role_id))
    db.session.commit()
    return _ok({'user_id': user_id, 'role_id': role_id})


@role_bp.route('/users/<int:user_id>/roles/<int:role_id>', methods=['DELETE'])
@require_auth
def remove_role(user_id, role_id):
    if not _check_perm('role.manage'):
        return _err('Permission denied', 403)

    user = User.query.get(user_id)
    if user is None:
        return _err('User not found', 404)

    # Idempotent: delete if exists, no error if not
    db.session.execute(
        user_roles.delete().where(
            user_roles.c.user_id == user_id,
            user_roles.c.role_id == role_id
        )
    )
    db.session.commit()
    return _ok({'user_id': user_id, 'role_id': role_id})

"""
T2 RBAC System -- Role Management Routes (Sample 1)

Strategy: Decorator-based permission checks, direct model manipulation.
Role inheritance cycle detection via recursive traversal.

Design decisions:
- Uses middleware.check_permission('role.manage') decorator
- Cycle detection: recursive _would_create_cycle() function that walks
  the parent chain upward from a proposed parent to see if it would
  eventually reach the target role
- Duplicate role name check: query by name + tenant_id before insert
- Cross-tenant role assignment check on POST /users/<id>/roles
- DELETE /users/<id>/roles/<role_id> is idempotent (no error if not assigned)
- PUT /roles/<id>/permissions replaces the full permission set via
  clearing and re-inserting on the role_permissions association table
"""

from flask import Blueprint, request, jsonify, g
from models import Role, Permission, User, role_permissions, user_roles
from middleware import check_permission
from app import db

role_bp = Blueprint('role_bp', __name__)


def _role_to_dict(role):
    """Convert Role model instance to dict for JSON response."""
    return {
        'id': role.id,
        'name': role.name,
        'tenant_id': role.tenant_id,
        'parent_role_id': role.parent_role_id,
        'permissions': [p.code for p in role.permissions],
    }


def _would_create_cycle(target_role_id, proposed_parent_id):
    """
    Recursively check if setting target_role's parent to proposed_parent
    would create a cycle in the inheritance chain.

    Walks upward from proposed_parent: if we ever reach target_role_id,
    it means target -> ... -> proposed_parent -> target would be a cycle.
    """
    if proposed_parent_id is None:
        return False
    if proposed_parent_id == target_role_id:
        return True
    parent = Role.query.get(proposed_parent_id)
    if parent is None or parent.parent_role_id is None:
        return False
    return _would_create_cycle(target_role_id, parent.parent_role_id)


def _resolve_permissions(perm_codes):
    """Resolve a list of permission code strings to Permission model instances.
    Creates new Permission records for any codes that don't exist yet.
    """
    perms = []
    for code in perm_codes:
        perm = Permission.query.filter_by(code=code).first()
        if perm is None:
            perm = Permission(code=code)
            db.session.add(perm)
        perms.append(perm)
    return perms


@role_bp.route('/roles', methods=['GET'])
@check_permission('role.manage')
def list_roles():
    roles = Role.query.filter_by(tenant_id=g.current_user.tenant_id).all()
    return jsonify({'status': 'ok', 'data': [_role_to_dict(r) for r in roles]}), 200


@role_bp.route('/roles', methods=['POST'])
@check_permission('role.manage')
def create_role():
    data = request.get_json(silent=True) or {}
    name = data.get('name')
    perm_codes = data.get('permissions', [])
    parent_role_id = data.get('parent_role_id')

    if not name:
        return jsonify({'status': 'error', 'message': 'Role name is required'}), 400

    # Check duplicate name within same tenant
    existing = Role.query.filter_by(name=name, tenant_id=g.current_user.tenant_id).first()
    if existing is not None:
        return jsonify({'status': 'error', 'message': 'Role name already exists'}), 409

    # Validate parent role (must exist and belong to same tenant)
    if parent_role_id is not None:
        parent = Role.query.get(parent_role_id)
        if parent is None or parent.tenant_id != g.current_user.tenant_id:
            return jsonify({'status': 'error', 'message': 'Invalid parent role'}), 400

    # Cycle check for parent
    # At creation time, the role doesn't exist yet, so no cycle is possible
    # unless parent_role_id points to itself (which is caught below)
    role = Role(
        tenant_id=g.current_user.tenant_id,
        name=name,
        parent_role_id=parent_role_id,
    )
    db.session.add(role)
    db.session.flush()  # Get the role.id

    # Assign permissions
    perms = _resolve_permissions(perm_codes)
